@Service
class SamlCredentialService {
    private final SamlProperties properties;
    private X509Credential signingCredential;

    SamlCredentialService(SamlProperties properties) {
        this.properties = properties;
    }

    @PostConstruct
    public void init() throws Exception {
        X509Certificate cert = X509Support.decodeCertificate(IOUtils.toString(properties.signingCertificate.getInputStream(), StandardCharsets.UTF_8));
        String pem = IOUtils.toString(properties.signingPrivateKey.getInputStream(), StandardCharsets.UTF_8)
                .replace("-----BEGIN PRIVATE KEY-----", "")
                .replace("-----END PRIVATE KEY-----", "")
                .replaceAll("\\s+", "");
        byte[] keyBytes = Base64.decodeBase64(pem);
        PrivateKey privateKey = KeyFactory.getInstance("RSA").generatePrivate(new PKCS8EncodedKeySpec(keyBytes));
        signingCredential = new BasicX509Credential(cert, privateKey);
    }

    public X509Credential getSigningCredential() {
        return signingCredential;
    }
}

